346	void Testbed::reload_network_from_json(const json& json, const std::string& config_base_path) {
347		// config_base_path is needed so that if the passed in json uses the 'parent' feature, we know where to look...
348		// be sure to use a filename, or if a directory, end with a trailing slash
349		m_network_config = merge_parent_network_config(json, config_base_path);
350		reset_network();
351	}
